                internal void BuildString(StringBuilder builder)
                {
                    if (_buffer == null)
                    {
                        return;
                    }

                    builder.Append('(');
                    builder.Append("MinTime=");
                    builder.Append(this.MinTime);
                    builder.Append('|');
                    builder.Append("MaxTime=");
                    builder.Append(this.MaxTime);
                    builder.Append('|');
                    builder.Append("SQLTime=");
                    builder.Append(this.SQLTime);
                    builder.Append('|');
                    builder.Append("TradeTime=");
                    builder.Append(this.TradeTime);
                    builder.Append('|');
                    builder.Append("HWTime=");
                    builder.Append(this.HWTime);
                    builder.Append('|');
                    builder.Append("DeltaAdjTime=");
                    builder.Append(this.DeltaAdjTime);
                    builder.Append('|');
                    builder.Append("DeltaAdjEdgeRefTime=");
                    builder.Append(this.DeltaAdjEdgeRefTime);
                    builder.Append('|');
                    builder.Append("LegCount=");
                    builder.Append(this.LegCount);
                    builder.Append('|');
                    builder.Append("Quantity=");
                    builder.Append(this.Quantity);
                    builder.Append('|');
                    builder.Append("BidSize=");
                    builder.Append(this.BidSize);
                    builder.Append('|');
                    builder.Append("AskSize=");
                    builder.Append(this.AskSize);
                    builder.Append('|');
                    builder.Append("SpreadID=");
                    builder.Append(this.SpreadID);
                    builder.Append('|');
                    builder.Append("TradeDelta=");
                    builder.Append(this.TradeDelta);
                    builder.Append('|');
                    builder.Append("HwTheta=");
                    builder.Append(this.HwTheta);
                    builder.Append('|');
                    builder.Append("HwVega=");
                    builder.Append(this.HwVega);
                    builder.Append('|');
                    builder.Append("HwGamma=");
                    builder.Append(this.HwGamma);
                    builder.Append('|');
                    builder.Append("HwRho=");
                    builder.Append(this.HwRho);
                    builder.Append('|');
                    builder.Append("TimeValue=");
                    builder.Append(this.TimeValue);
                    builder.Append('|');
                    builder.Append("IntrinsicValue=");
                    builder.Append(this.IntrinsicValue);
                    builder.Append('|');
                    builder.Append("FvDivs=");
                    builder.Append(this.FvDivs);
                    builder.Append('|');
                    builder.Append("UFwd=");
